<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Maze Exploration Bots</title>
    <style>
        body {
            background: #222;
            color: #eee;
            font-family: sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            margin: 0;
            padding: 20px;
        }
        #ui {
            margin-bottom: 15px;
            display: flex;
            gap: 20px;
            align-items: center;
            font-size: 18px;
            background: #333;
            padding: 10px 20px;
            border-radius: 8px;
        }
        #maze {
            position: relative;
            box-shadow: 0 0 20px rgba(0,0,0,0.5);
        }
        canvas {
            display: block;
            background: #111;
        }
        button {
            padding: 8px 16px;
            cursor: pointer;
            font-size: 16px;
            background: #555;
            color: white;
            border: none;
            border-radius: 4px;
        }
        button:hover { background: #777; }
    </style>
</head>
<body>

<div id="ui">
    <div>Ticks: <span id="timer">0</span></div>
    <div>Completed: <span id="completed">0</span>/24</div>
    <button id="reset">Reset Maze</button>
</div>
<div id="maze">
    <canvas id="gameCanvas"></canvas>
</div>

<script>
/** 
 * DETERMINISTIC RNG 
 */
function mulberry32(a) {
    return function() {
        let t = a += 0x6D2B79F5;
        t = Math.imul(t ^ t >>> 15, t | 1);
        t ^= t + Math.imul(t ^ t >>> 7, t | 61);
        return ((t ^ t >>> 14) >>> 0) / 4294967296;
    }
}

/**
 * GAME ENGINE
 */
const Game = {
    rows: 20,
    cols: 20,
    spawn: { r: 0, c: 0 },
    exit: { r: 19, c: 19 },
    elapsed: 0,
    mazeData: [], // walls[r][c] = {n, e, s, w}
    bots: [],

    reset(seed) {
        const rng = mulberry32(seed || Math.floor(Math.random() * 1e9));
        this.elapsed = 0;
        this.rows = 20;
        this.cols = 20;
        this.spawn = { r: 0, c: 0 };
        this.exit = { r: this.rows - 1, c: this.cols - 1 };

        // Initialize walls
        this.mazeData = Array.from({ length: this.rows }, () => 
            Array.from({ length: this.cols }, () => ({ n: true, e: true, s: true, w: true }))
        );

        // Generate Perfect Maze (Recursive Backtracker)
        const visited = Array.from({ length: this.rows }, () => Array(this.cols).fill(false));
        const stack = [{ r: 0, c: 0 }];
        visited[0][0] = true;

        while (stack.length > 0) {
            const curr = stack[stack.length - 1];
            const neighbors = [];
            if (curr.r > 0 && !visited[curr.r - 1][curr.c]) neighbors.push({ r: curr.r - 1, c: curr.c, dir: 'n', opp: 's' });
            if (curr.c < this.cols - 1 && !visited[curr.r][curr.c + 1]) neighbors.push({ r: curr.r, c: curr.c + 1, dir: 'e', opp: 'w' });
            if (curr.r < this.rows - 1 && !visited[curr.r + 1][curr.c]) neighbors.push({ r: curr.r + 1, c: curr.c, dir: 's', opp: 'n' });
            if (curr.c > 0 && !visited[curr.r][curr.c - 1]) neighbors.push({ r: curr.r, c: curr.c - 1, dir: 'w', opp: 'e' });

            if (neighbors.length > 0) {
                const next = neighbors[Math.floor(rng() * neighbors.length)];
                this.mazeData[curr.r][curr.c][next.dir] = false;
                this.mazeData[next.r][next.c][next.opp] = false;
                visited[next.r][next.c] = true;
                stack.push(next);
            } else {
                stack.pop();
            }
        }

        // Initialize 24 Bots
        this.bots = [];
        for (let i = 0; i < 24; i++) {
            const botRng = mulberry32(seed ? seed + i + 1 : Math.floor(Math.random() * 1e9) + i);
            const dirs = ['n', 'e', 's', 'w'];
            // Shuffle preference order for each bot
            for (let j = dirs.length - 1; j > 0; j--) {
                const k = Math.floor(botRng() * (j + 1));
                [dirs[j], dirs[k]] = [dirs[k], dirs[j]];
            }

            this.bots.push({
                id: i,
                r: this.spawn.r,
                c: this.spawn.c,
                path: [{ r: this.spawn.r, c: this.spawn.c }],
                visited: new Set(["0,0"]),
                deadEnds: [],
                finishTick: null,
                pref: dirs,
                color: `hsl(${(i * 360 / 24)}, 80%, 60%)`
            });
        }
    },

    walls(r, c) {
        return this.mazeData[r][c];
    },

    tick(n) {
        for (let i = 0; i < n; i++) {
            const allFinished = this.bots.every(b => b.finishTick !== null);
            if (allFinished) break;

            this.elapsed++;

            this.bots.forEach(bot => {
                if (bot.finishTick !== null) return;

                // Check if arrived at exit
                if (bot.r === this.exit.r && bot.c === this.exit.c) {
                    bot.finishTick = this.elapsed;
                    return;
                }

                const cellWalls = this.mazeData[bot.r][bot.c];
                let moved = false;

                // Try to move to an unvisited neighbor based on preference
                for (const dir of bot.pref) {
                    if (cellWalls[dir]) continue; // Wall exists

                    let nr = bot.r, nc = bot.c;
                    if (dir === 'n') nr--; else if (dir === 'e') nc++; else if (dir === 's') nr++; else if (dir === 'w') nc--;

                    if (!bot.visited.has(`${nr},${nc}`)) {
                        bot.r = nr;
                        bot.c = nc;
                        bot.path.push({ r: nr, c: nc });
                        bot.visited.add(`${nr},${nc}`);
                        moved = true;
                        break;
                    }
                }

                if (!moved) {
                    // Mark current as dead end and backtrack
                    const currentPosStr = `${bot.r},${bot.c}`;
                    if (!bot.deadEnds.some(p => p.r === bot.r && p.c === bot.c)) {
                        bot.deadEnds.push({ r: bot.r, c: bot.c });
                    }

                    // Backtrack to previous cell in path
                    if (bot.path.length > 1) {
                        bot.path.pop(); // Remove current
                        const prev = bot.path[bot.path.length - 1];
                        bot.r = prev.r;
                        bot.c = prev.c;
                        bot.path.push({ r: bot.r, c: bot.c });
                    }
                }

                // Check exit again after move
                if (bot.r === this.exit.r && bot.c === this.exit.c) {
                    bot.finishTick = this.elapsed;
                }
            });
        }
    }
};

window.game = Game;

/**
 * RENDERING & UI
 */
const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');
const timerEl = document.getElementById('timer');
const completedEl = document.getElementById('completed');
const resetBtn = document.getElementById('reset');

const CELL_SIZE = 30;
canvas.width = Game.cols * CELL_SIZE;
canvas.height = Game.rows * CELL_SIZE;

// For smooth interpolation
let visualBots = [];

function updateUI() {
    timerEl.textContent = Game.elapsed;
    completedEl.textContent = Game.bots.filter(b => b.finishTick !== null).length;
}

function draw() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Draw Maze Walls
    ctx.strokeStyle = '#fff';
    ctx.lineWidth = 2;
    for (let r = 0; r < Game.rows; r++) {
        for (let c = 0; c < Game.cols; c++) {
            const w = Game.walls(r, c);
            const x = c * CELL_SIZE;
            const y = r * CELL_SIZE;
            ctx.beginPath();
            if (w.n) { ctx.moveTo(x, y); ctx.lineTo(x + CELL_SIZE, y); }
            if (w.e) { ctx.moveTo(x + CELL_SIZE, y); ctx.lineTo(x + CELL_SIZE, y + CELL_SIZE); }
            if (w.s) { ctx.moveTo(x, y + CELL_SIZE); ctx.lineTo(x + CELL_SIZE, y + CELL_SIZE); }
            if (w.w) { ctx.moveTo(x, y); ctx.lineTo(x, y + CELL_SIZE); }
            ctx.stroke();
        }
    }

    // Draw Spawn and Exit
    ctx.fillStyle = '#0f0';
    ctx.fillRect(Game.spawn.c * CELL_SIZE + 5, Game.spawn.r * CELL_SIZE + 5, CELL_SIZE - 10, CELL_SIZE - 10);
    ctx.fillStyle = '#f00';
    ctx.fillRect(Game.exit.c * CELL_SIZE + 5, Game.exit.r * CELL_SIZE + 5, CELL_SIZE - 10, CELL_SIZE - 10);

    // Draw Bots with interpolation
    visualBots.forEach((vb, i) => {
        const bot = Game.bots[i];
        // Lerp visual position towards logical position
        vb.x += (bot.c * CELL_SIZE + CELL_SIZE / 2 - vb.x) * 0.15;
        vb.y += (bot.r * CELL_SIZE + CELL_SIZE / 2 - vb.y) * 0.15;

        ctx.fillStyle = bot.color;
        ctx.beginPath();
        ctx.arc(vb.x, vb.y, 4, 0, Math.PI * 2);
        ctx.fill();
    });

    updateUI();
    requestAnimationFrame(draw);
}

function init() {
    Game.reset();
    visualBots = Game.bots.map(b => ({
        x: b.c * CELL_SIZE + CELL_SIZE / 2,
        y: b.r * CELL_SIZE + CELL_SIZE / 2
    }));
}

resetBtn.addEventListener('click', () => {
    init();
});

// Simulation loop
setInterval(() => {
    Game.tick(1);
}, 100);

init();
draw();

</script>
</body>
</html>
